const t=document.getElementById("menu-toggle"),n=document.getElementById("mobile-menu"),d=document.getElementById("menu-icon-open"),s=document.getElementById("menu-icon-close");t?.addEventListener("click",()=>{const e=n?.classList.contains("hidden");n?.classList.toggle("hidden"),d?.classList.toggle("hidden",!e),s?.classList.toggle("hidden",e),t.setAttribute("aria-expanded",String(e))});n?.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{n.classList.add("hidden"),d?.classList.remove("hidden"),s?.classList.add("hidden")})});
